using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentService(HttpClient http)
{
    public async Task<List<ShipmentDto>> GetAllShipmentsAsync()
    {
        return await http.GetFromJsonAsync<List<ShipmentDto>>("/api/shipments") ?? [];
    }

    public async Task<List<ShipmentDto>> GetMyShipmentsAsync()
    {
        return await http.GetFromJsonAsync<List<ShipmentDto>>("/api/shipments/my") ?? [];
    }

    public async Task<ShipmentDto?> TrackShipmentAsync(string trackingNumber)
    {
        var response = await http.GetAsync($"/api/shipments/track/{trackingNumber}");
        if (!response.IsSuccessStatusCode) return null;
        return await response.Content.ReadFromJsonAsync<ShipmentDto>();
    }

    public async Task<bool> UpdateStatusAsync(int id, ShipmentStatus status, DateTime? estimatedDelivery = null)
    {
        var response = await http.PutAsJsonAsync($"/api/shipments/{id}/status",
            new { Status = status, EstimatedDelivery = estimatedDelivery });
        return response.IsSuccessStatusCode;
    }
}

