    <div class="col-md-2">
        <button class="btn btn-primary" @onclick="LoadShipments">
            Refresh
        </button>
    </div>
</div>

@if (loading)
{
    <p><em>Loading shipments...</em></p>
}
else if (shipments is null || shipments.Count == 0)
{
    <p>No shipments found.</p>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Customer</th>
                <th>Est. Delivery</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in FilteredShipments)
            {
                <tr>
                    <td><strong>@shipment.TrackingNumber</strong></td>
                    <td>@shipment.Origin</td>
                    <td>@shipment.Destination</td>
                    <td>
                        <span class="badge @GetStatusBadgeClass(shipment.Status)">
                            @shipment.Status
                        </span>
                    </td>
                    <td>@shipment.CustomerEmail</td>
                    <td>@shipment.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
                    <td>
                        <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                value="@shipment.Status"
                                @onchange="(e) => UpdateStatus(shipment, e)">
                            @foreach (var status in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@status">@status</option>
                            }
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>

    <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
}

@code {
    private List<ShipmentDto>? shipments;
    private bool loading = true;
    private string filterText = string.Empty;
    private string statusFilter = string.Empty;

    private IEnumerable<ShipmentDto> FilteredShipments =>
        (shipments ?? [])
            .Where(s => string.IsNullOrEmpty(filterText) ||
                        s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
                        s.TrackingNumber.Contains(filterText, StringComparison.OrdinalIgnoreCase))
            .Where(s => string.IsNullOrEmpty(statusFilter) ||
                        s.Status.ToString() == statusFilter);

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        loading = true;
        shipments = await ShipmentService.GetAllShipmentsAsync();
        loading = false;
    }

    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            var success = await ShipmentService.UpdateStatusAsync(shipment.Id, newStatus);
            if (success)
            {
                shipment.Status = newStatus;
            }
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/tracking"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@rendermode InteractiveAuto
@inject ShipmentService ShipmentService

<PageTitle>My Shipments</PageTitle>

<h2>My Shipments</h2>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number..."
                   @bind="trackingInput" @onkeyup="HandleKeyUp" />
            <button class="btn btn-outline-primary" @onclick="TrackShipment">
                Track
            </button>
        </div>
    </div>
</div>

@if (trackedShipment is not null)
{
    <div class="card mb-4 border-primary">
        <div class="card-header bg-primary text-white">
            Tracking Result: @trackedShipment.TrackingNumber
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <p><strong>From:</strong> @trackedShipment.Origin</p>
                    <p><strong>To:</strong> @trackedShipment.Destination</p>
                    <p><strong>Description:</strong> @trackedShipment.Description</p>
                </div>
                <div class="col-md-6">
                    <p><strong>Status:</strong>
                        <span class="badge @GetStatusBadgeClass(trackedShipment.Status)">
                            @trackedShipment.Status
                        </span>
                    </p>
                    <p><strong>Shipped:</strong> @trackedShipment.ShippedDate.ToString("MMM dd, yyyy")</p>
                    <p><strong>Estimated Delivery:</strong>
                        <span class="@(trackedShipment.EstimatedDelivery < DateTime.UtcNow && trackedShipment.Status != ShipmentStatus.Delivered ? "text-danger fw-bold" : "")">
                            @trackedShipment.EstimatedDelivery.ToString("MMM dd, yyyy")
                        </span>
                    </p>
                </div>
            </div>
        </div>
    </div>
}
else if (trackingNotFound)
{
    <div class="alert alert-warning">No shipment found with that tracking number.</div>
}

<h4 class="mt-4">Your Shipments</h4>

@if (loading)
{
    <p><em>Loading your shipments...</em></p>
}
else if (myShipments is null || myShipments.Count == 0)
{
    <p class="text-muted">No shipments associated with your account.</p>
}
else
{
    <div class="row">
        @foreach (var shipment in myShipments)
        {
            <div class="col-md-6 col-lg-4 mb-3">
                <div class="card h-100">
                    <div class="card-body">
                        <h6 class="card-title">@shipment.TrackingNumber</h6>
                        <p class="card-text mb-1">
                            <small class="text-muted">@shipment.Origin → @shipment.Destination</small>
                        </p>
                        <p class="card-text mb-1">@shipment.Description</p>
                        <span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span>
                    </div>
                    <div class="card-footer">
                        <small>
                            Est. Delivery:
                            <strong>@shipment.EstimatedDelivery.ToString("MMM dd, yyyy")</strong>
                        </small>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private List<ShipmentDto>? myShipments;
    private ShipmentDto? trackedShipment;
    private bool loading = true;
    private bool trackingNotFound;
    private string trackingInput = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        myShipments = await ShipmentService.GetMyShipmentsAsync();
        loading = false;
    }

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingInput)) return;

        trackingNotFound = false;
        trackedShipment = await ShipmentService.TrackShipmentAsync(trackingInput.Trim());
        trackingNotFound = trackedShipment is null;
    }

    private async Task HandleKeyUp(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackShipment();
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };
}

